        <div
          key={i}
          style={{
            opacity: (i + 1) * 0.1,
            marginTop: fibonacci(i) + 2,
          }}
          className="w-full"
        >
          <div className="h-px w-full bg-foreground/10" />
        </div>
      ))}
      {children}
    </div>
