        aria-hidden="true"
        className="relative flex flex-col items-center justify-center"
        style={{ width: iconSize, height: iconSize }}
      >
        {[0, 1, 2].map((i) => (
          <span
            key={i}
            className={cn(
              "absolute bg-current transition-[transform,opacity] ease-out",
              isOpen && i === 0 && "opacity-0",
              isOpen && i === 1 && "rotate-45",
              isOpen && i === 2 && "-rotate-45",
            )}
            style={{
              transitionDuration: `${Math.min(animationDuration, 180)}ms`,
              width: lineWidth,
              height: lineHeight,
              top: isOpen
                ? `calc(50% - ${lineHeight / 2}px)`
                : `calc(50% + ${(i - 1) * lineSpacing}px - ${lineHeight / 2}px)`,
            }}
          />
        ))}
      </span>
    </button>
  );
}

export default function FlowerMenu({
  menuItems,
  iconColor = "hsl(var(--primary-foreground))",
  backgroundColor = "hsl(var(--foreground))",
  animationDuration = 220,
  togglerSize = 44,
  petalGap = 28,
  triggerLabel = "Open links menu",
  menuLabel = "Menu",
  className,
  ...props
}: FlowerMenuProps) {
  const menuId = useId();
  const rootRef = useRef<HTMLElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const itemRefs = useRef<Array<HTMLAnchorElement | null>>([]);
  const [isOpen, setIsOpen] = useState(false);

  const itemCount = menuItems.length;
  const safeTogglerSize = Math.max(44, togglerSize);
  const itemSize = safeTogglerSize;
  const iconSize = Math.max(20, Math.floor(safeTogglerSize * 0.45));
  const orbitRadius = itemSize + petalGap;
  const containerSize = (orbitRadius + itemSize / 2) * 2 + 8;

  const close = useCallback(() => {
    setIsOpen(false);
    triggerRef.current?.focus();
  }, []);

  const toggle = useCallback(() => {
    setIsOpen((value) => !value);
  }, []);

  useEffect(() => {
    if (!isOpen) return;

    const onPointerDown = (event: PointerEvent) => {
      if (rootRef.current?.contains(event.target as Node)) return;
      setIsOpen(false);
    };

    document.addEventListener("pointerdown", onPointerDown);
    return () => document.removeEventListener("pointerdown", onPointerDown);
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) return;
    itemRefs.current[0]?.focus();
  }, [isOpen]);

  const focusItem = (index: number) => {
    if (itemCount === 0) return;
    const next = (index + itemCount) % itemCount;
    itemRefs.current[next]?.focus();
  };

  const onMenuKeyDown = (event: React.KeyboardEvent<HTMLUListElement>) => {
    const activeIndex = itemRefs.current.findIndex((node) => node === document.activeElement);

    switch (event.key) {
      case "Escape":
        event.preventDefault();
        close();
        break;
      case "Tab":
        setIsOpen(false);
        break;
      case "Home":
        event.preventDefault();
        itemRefs.current[0]?.focus();
        break;
      case "End":
        event.preventDefault();
        itemRefs.current[itemCount - 1]?.focus();
        break;
      case "ArrowRight":
      case "ArrowDown":
        event.preventDefault();
        focusItem(activeIndex < 0 ? 0 : activeIndex + 1);
        break;
      case "ArrowLeft":
      case "ArrowUp":
        event.preventDefault();
        focusItem(activeIndex <= 0 ? itemCount - 1 : activeIndex - 1);
        break;
    }
  };

  return (
    <nav
      ref={rootRef}
      aria-label={menuLabel}
      className={cn("relative mx-auto", className)}
      style={{ width: containerSize, height: containerSize, minHeight: containerSize }}
      {...props}
    >
      <MenuToggler
        isOpen={isOpen}
        onToggle={toggle}
        backgroundColor={backgroundColor}
        iconColor={iconColor}
        animationDuration={animationDuration}
        togglerSize={safeTogglerSize}
        iconSize={iconSize}
        controlsId={menuId}
        triggerLabel={triggerLabel}
        buttonRef={triggerRef}
      />

      <ul
        id={menuId}
        role="menu"
        aria-orientation="vertical"
        inert={!isOpen ? true : undefined}
        onKeyDown={onMenuKeyDown}
        className="absolute inset-0 m-0 list-none p-0"
      >
        {menuItems.map((item, index) => {
          const Icon = item.icon;
          const angle = (360 / itemCount) * index;
          const openDelay = 10 + index * 20;
          const closeDelay = (itemCount - 1 - index) * 14;

          return (
            <li
              key={item.key ?? item.href}
              role="none"
              className={cn(
                "flower-petal pointer-events-none absolute inset-0 m-auto opacity-0",
                isOpen && "pointer-events-auto opacity-100",
              )}
              style={{
                width: itemSize,
                height: itemSize,
                transitionDuration: `${animationDuration}ms`,
                transitionDelay: isOpen ? `${openDelay}ms` : `${closeDelay}ms`,
                transform: isOpen
                  ? `rotate(${angle}deg) translateX(-${orbitRadius}px) scale(1)`
                  : "rotate(0deg) translateX(0) scale(0.72)",
              }}
            >
              <Link
                ref={(node) => {
                  itemRefs.current[index] = node;
                }}
                href={item.href}
                target="_blank"
                rel="noopener noreferrer"
                role="menuitem"
                aria-label={item.label}
                tabIndex={isOpen ? 0 : -1}
                className={cn(
                  "flex size-full touch-manipulation items-center justify-center rounded-full transition-all duration-150 ease-out focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background active:scale-95",
                  isOpen ? "opacity-100" : "opacity-0",
                  "hover:scale-110 focus-visible:scale-110",
                )}
                style={{
                  backgroundColor,
                  color: iconColor,
                  transform: `rotate(-${angle}deg)`,
                }}
                onClick={() => setIsOpen(false)}
              >
                <span className="sr-only">{item.label}</span>
                <Icon aria-hidden="true" style={{ width: iconSize, height: iconSize }} />
              </Link>
            </li>
          );
        })}
      </ul>
    </nav>
  );
}

"use client";

import { Plus } from "lucide-react";
import type React from "react";
import { useCallback, useEffect, useId, useRef, useState } from "react";

import { cn } from "@/lib/utils";

import "./speed-dial.css";

type Direction = "up" | "down" | "left" | "right";

interface SpeedDialAction {
  icon: React.ReactNode;
  label: string;
  key: string;
  action: () => void;
}

interface SpeedDialProps extends React.HTMLAttributes<HTMLDivElement> {
  direction?: Direction;
  actionButtons: SpeedDialAction[];
  /** Accessible name for the main toggle when closed. */
  triggerLabel?: string;
}

const shellClass =
  "flex size-11 shrink-0 touch-manipulation items-center justify-center rounded-xl border border-border/80 bg-background/85 text-foreground shadow-lg backdrop-blur-xl transition-colors hover:bg-accent/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-background active:scale-[0.97]";

const menuAnchorClass: Record<Direction, string> = {
  up: "bottom-full left-1/2 mb-2 -translate-x-1/2 origin-bottom",
  down: "top-full left-1/2 mt-2 -translate-x-1/2 origin-top",
  left: "right-full top-1/2 mr-2 -translate-y-1/2 origin-right",
  right: "left-full top-1/2 ml-2 -translate-y-1/2 origin-left",
};

const menuLayoutClass: Record<Direction, string> = {
  up: "flex flex-col-reverse items-center gap-2.5",
  down: "flex flex-col items-center gap-2.5",
  left: "flex flex-row-reverse items-center gap-2.5",
  right: "flex flex-row items-center gap-2.5",
};

function arrowKeysForDirection(direction: Direction) {
  if (direction === "up") return { prev: "ArrowDown", next: "ArrowUp" };
  if (direction === "down") return { prev: "ArrowUp", next: "ArrowDown" };
  if (direction === "left") return { prev: "ArrowRight", next: "ArrowLeft" };
  return { prev: "ArrowLeft", next: "ArrowRight" };
}

export default function SpeedDial({
  direction = "right",
  actionButtons,
  triggerLabel = "Open actions menu",
  className,
  ...props
}: SpeedDialProps) {
  const menuId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const triggerRef = useRef<HTMLButtonElement>(null);
  const itemRefs = useRef<Array<HTMLButtonElement | null>>([]);
  const [open, setOpen] = useState(false);

  const close = useCallback(() => {
    setOpen(false);
    triggerRef.current?.focus();
  }, []);

  const toggle = useCallback(() => {
    setOpen((value) => !value);
  }, []);

  useEffect(() => {
    if (!open) return;

    const onPointerDown = (event: PointerEvent) => {
      if (rootRef.current?.contains(event.target as Node)) return;
      setOpen(false);
    };

    document.addEventListener("pointerdown", onPointerDown);
    return () => document.removeEventListener("pointerdown", onPointerDown);
  }, [open]);

  useEffect(() => {
    if (!open) return;
    itemRefs.current[0]?.focus();
  }, [open]);

  const focusItem = (index: number) => {
    const count = actionButtons.length;
    if (count === 0) return;
    const next = (index + count) % count;
    itemRefs.current[next]?.focus();
  };

  const onMenuKeyDown = (event: React.KeyboardEvent<HTMLUListElement>) => {
    const { prev, next } = arrowKeysForDirection(direction);
    const activeIndex = itemRefs.current.findIndex((node) => node === document.activeElement);

    switch (event.key) {
      case "Escape":
        event.preventDefault();
        close();
        break;
      case "Tab":
        setOpen(false);
        break;
      case "Home":
        event.preventDefault();
        itemRefs.current[0]?.focus();
        break;
      case "End":
        event.preventDefault();
        itemRefs.current[actionButtons.length - 1]?.focus();
        break;
      default:
        if (event.key === prev) {
          event.preventDefault();
          focusItem(activeIndex <= 0 ? actionButtons.length - 1 : activeIndex - 1);
        } else if (event.key === next) {
          event.preventDefault();
          focusItem(activeIndex < 0 ? 0 : activeIndex + 1);
        }
    }
  };

  return (
    <div
      ref={rootRef}
      className={cn("relative inline-flex", className)}
      data-direction={direction}
      {...props}
    >
      <button
        ref={triggerRef}
        type="button"
        className={cn(shellClass, "relative z-20")}
        aria-expanded={open}
        aria-haspopup="menu"
        aria-controls={menuId}
        aria-label={open ? "Close actions menu" : triggerLabel}
        onClick={toggle}
      >
        <span
          aria-hidden="true"
          className={cn(
            "speed-dial-trigger-icon flex items-center justify-center transition-transform duration-150 ease-out",
            open && "rotate-45",
          )}
        >
          <Plus className="size-5" strokeWidth={2.25} />
        </span>
      </button>

      {open ? (
        <ul
          id={menuId}
          role="menu"
          aria-orientation={direction === "up" || direction === "down" ? "vertical" : "horizontal"}
          onKeyDown={onMenuKeyDown}
          className={cn(
            "absolute z-10 m-0 list-none p-0",
            menuAnchorClass[direction],
            menuLayoutClass[direction],
          )}
        >
          {actionButtons.map((action, index) => (
            <li
              key={action.key}
              role="none"
              className="speed-dial-item list-none"
              style={{ "--i": index } as React.CSSProperties}
            >
              <button
                ref={(node) => {
                  itemRefs.current[index] = node;
                }}
                type="button"
                role="menuitem"
                className={shellClass}
                aria-label={action.label}
                onClick={() => {
                  action.action();
                  close();
                }}
              >
                <span className="sr-only">{action.label}</span>
                <span
                  aria-hidden="true"
                  className="flex size-5 items-center justify-center [&>svg]:size-5"
                >
                  {action.icon}
                </span>
              </button>
            </li>
          ))}
        </ul>
      ) : null}
    </div>
  );
}

