const JOIN = "round" as const;

/** Horizontally centered rounded bar. */
function Bar({
  cx,
  y,
  w,
  h = 3.5,
  r,
  fill = INK,
  o,
  className,
}: {
  cx: number;
  y: number;
  w: number;
  h?: number;
  r?: number;
  fill?: string;
  o?: number;
  className?: string;
}) {
  return (
    <rect
      x={cx - w / 2}
      y={y}
      width={w}
      height={h}
      rx={r ?? h / 2}
      fill={fill}
      opacity={o}
      className={className}
    />
  );
}

