type GooeyTabsContextValue = {
  activeIndex: number;
  setActiveIndex: (index: number) => void;
  focusedIndex: number;
  setFocusedIndex: (index: number) => void;
  filterId: string;
  intensity: number;
  contrast: number;
  lightness: number;
};

const GooeyTabsContext = createContext<GooeyTabsContextValue | null>(null);

type GooeyTabSlotContextValue = {
  index: number;
  count: number;
};

const GooeyTabSlotContext = createContext<GooeyTabSlotContextValue | null>(null);

function useGooeyTabs() {
  const context = use(GooeyTabsContext);
  if (!context) {
    throw new Error("GooeyTabs primitives must be used within <GooeyTabs>.");
  }
  return context;
}

function GooeyTabSlot({
  index,
  count,
  children,
}: {
  index: number;
  count: number;
  children: ReactNode;
}) {
  const value = useMemo(() => ({ index, count }), [index, count]);
  return <GooeyTabSlotContext.Provider value={value}>{children}</GooeyTabSlotContext.Provider>;
