        aria-hidden
        className={cn(
          "pointer-events-none absolute -bottom-px left-1/2 h-[3px] w-0 -translate-x-1/2 rounded-full",
          "transition-[width] duration-500 ease-[cubic-bezier(0.22,1,0.36,1)]",
