    chip: "bg-rose-500/15 dark:bg-rose-500/25",
    dot: "bg-rose-600",
    title: "text-foreground",
    time: "text-muted-foreground",
  },
};

function eventTimeStart(time: string) {
  const parts = time.split(/\s[–-]\s/);
  return parts[0]?.trim() ?? time;
}

function EventRow({ event }: { event: CalendarEventItem }) {
  const variant = VARIANT_STYLES[event.variant ?? "violet"];
  return (
    <li className={cn("flex shrink-0 gap-2 rounded-md px-2 py-1", variant.chip)}>
      <span className={cn("mt-1.5 size-2 shrink-0 rounded-full", variant.dot)} aria-hidden />
      <div className="flex min-w-0 flex-1 flex-col gap-0.5">
        <p className={cn("truncate text-[15px] font-semibold leading-snug", variant.title)}>
          {event.title}
        </p>
        <p className={cn("truncate text-[13px] leading-snug tabular-nums", variant.time)}>
          {event.time}
        </p>
      </div>
    </li>
  );
}

export default function CalendarEvent({
  className,
  date = new Date(),
  events = DEFAULT_CALENDAR_EVENTS,
  maxVisible = 2,
}: CalendarEventProps) {
  const list = events;
  const visible = list.slice(0, maxVisible);
  const extra = list.length - maxVisible;
  const nextEvent = list[maxVisible];

  return (
    <div
      className={cn(
        "flex size-52 flex-col rounded-3xl border border-border bg-background p-3.5 font-sans shadow-md",
        className,
      )}
    >
      <div className="flex shrink-0 items-baseline gap-1.5">
        <p className="text-[15px] font-semibold leading-snug text-rose-500">
          {date.toLocaleString("default", { weekday: "short" })}
        </p>
        <p className="text-[22px] font-normal leading-snug tabular-nums tracking-tight text-foreground">
          {date.getDate()}
        </p>
      </div>

      {visible.length > 0 ? (
        <ul className="mt-2 flex shrink-0 flex-col gap-1">
          {visible.map((event, index) => (
            <EventRow key={`${event.title}-${index}`} event={event} />
          ))}
        </ul>
      ) : (
        <p className="mt-2 shrink-0 text-[13px] leading-snug text-muted-foreground">
          No events today
        </p>
      )}

      {extra > 0 ? (
        <div className="mt-1.5 flex h-8 shrink-0 items-center justify-between gap-2 rounded-md bg-muted/60 px-2.5">
          <p className="shrink-0 text-[13px] font-medium leading-snug text-foreground">
            +{extra} more
          </p>
          <p className="min-w-0 truncate text-right text-[13px] leading-snug tabular-nums text-muted-foreground">
            {nextEvent ? eventTimeStart(nextEvent.time) : ""}
          </p>
        </div>
      ) : null}
    </div>
  );
}

import { Calendar as CalendarIcon, DotIcon } from "lucide-react";
import { AnimatePresence, motion } from "motion/react";
import { useRef, useState } from "react";

const monthArray = [
  "",
  "January",
  "February",
  "March",
  "April",
  "May",
  "June",
  "July",
  "August",
  "September",
  "October",
  "November",
  "December",
];

interface EventType {
  date: number;
  title: string;
  time: string;
}

const EMPTY_CALENDAR_EVENTS: EventType[] = [];

export default function CalendarWidget({
  initialSelectedDate = 1,
  initialShowEvents = true,
  eventsData,
  month = 1,
  year = new Date().getFullYear(),
}: {
  initialSelectedDate?: number;
  initialShowEvents?: boolean;
  eventsData?: EventType[];
  month?: number;
  year?: number;
}) {
  const resolvedEvents = eventsData ?? EMPTY_CALENDAR_EVENTS;
  const [selectedDate, setSelectedDate] = useState(initialSelectedDate);
  const [showEvents, setShowEvents] = useState(initialShowEvents);
  const scrollRef = useRef<HTMLDivElement>(null);

  const dates = Array.from({ length: 30 }, (_, i) => i + 1);
  const daySymbols = ["S", "M", "T", "W", "T", "F", "S"];

  const filteredEvents = resolvedEvents.filter((event: EventType) => event.date === selectedDate);

  const scrollToDate = (date: number) => {
    const selectedElement = scrollRef.current?.querySelector(`[data-date="${date}"]`);
    selectedElement?.scrollIntoView({ behavior: "smooth", inline: "center", block: "nearest" });
  };

  return (
    <motion.div
      className="mx-auto max-w-sm rounded-3xl bg-slate-200 shadow-lg"
      initial={{ scale: 0.9, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      transition={{ duration: 0.3 }}
    >
      <div className="mx-auto max-w-sm rounded-3xl px-6 py-2">
        <h2 className="mb-4 text-2xl font-bold">{`${monthArray[month]} ${year}`}</h2>
        <div
          ref={scrollRef}
          className="scrollbar-hide flex items-start space-x-2 overflow-x-auto py-2"
          style={{ scrollbarWidth: "none", msOverflowStyle: "none" }}
        >
          {dates.map((date, index) => (
            <motion.button
              key={date}
              data-date={date}
              className="flex w-10 shrink-0 flex-col items-center justify-center gap-y-2 rounded-lg"
              onClick={() => {
                setSelectedDate(date);
                scrollToDate(date);
                setShowEvents(true);
              }}
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.95 }}
            >
              <span className="mb-1 text-xs">{daySymbols[(index + 4) % 7]}</span>
              <AnimatePresence>
                {selectedDate === date ? (
                  <motion.span
                    layoutId="highlighted-date"
                    className="flex h-8 w-8 items-center justify-center rounded-full bg-gray-100 text-black shadow-lg"
                    transition={{
                      type: "spring",
                      stiffness: 300,
                      damping: 20,
                    }}
                  >
                    {date}
                  </motion.span>
                ) : (
                  <span className="flex h-8 w-8 items-center justify-center">{date}</span>
                )}
              </AnimatePresence>
              <span>
                {eventsData?.find((alldates: EventType) => alldates.date === date) ? (
                  <DotIcon />
                ) : (
                  ""
                )}
              </span>
            </motion.button>
          ))}
        </div>
      </div>

      <div className="w-full rounded-3xl bg-[#fefefe] px-6 shadow-lg">
        <AnimatePresence mode="wait">
          {showEvents && (
            <motion.div
              key="events"
              className="scrollbar-hide mt-2 h-[150px] overflow-scroll border-t pt-4"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              transition={{ duration: 0.2 }}
            >
              {filteredEvents.length > 0 ? (
                filteredEvents.map((event: EventType, index: number) => (
                  <motion.div
                    key={index}
                    className="mb-2 border-b-2 border-slate-200"
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: index * 0.1 }}
                  >
                    <h4 className="font-medium">{event.title}</h4>
                    <p className="text-sm text-gray-500">{event.time}</p>
                  </motion.div>
                ))
              ) : (
                <motion.div
                  className="flex flex-col items-center text-gray-500"
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                >
                  <CalendarIcon className="mb-2 h-8 w-8" />
                  <p>No Events</p>
                </motion.div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </motion.div>
  );
}

