"use client";
/* eslint-disable @next/next/no-img-element */
import { useEffect, useState } from "react";

import { absoluteUrl, cn } from "@/lib/utils";

const getTime = () => {
  const now = new Date();
  const hours = now.getHours();
  const minutes = now.getMinutes();

  return {
    hoursTens: Math.floor(hours / 10),
    hoursOnes: hours % 10,
    minutesTens: Math.floor(minutes / 10),
    minutesOnes: minutes % 10,
  };
};

export default function ClockWithPhoto() {
  const [time, setTime] = useState(getTime);

  useEffect(() => {
    let timeout: NodeJS.Timeout;
    const updateTime = () => {
      const now = new Date();
      const secondsUntilNextMinute = 60 - now.getSeconds();
      setTime(getTime());
      timeout = setTimeout(updateTime, secondsUntilNextMinute * 1000);
    };

    timeout = setTimeout(updateTime, 0);

    return () => clearTimeout(timeout);
  }, []);

  return (
    <div className="group/clock relative h-52 w-52 gap-2 overflow-hidden rounded-3xl">
      <div className="relative flex h-full w-full items-center">
        <img
          src="https://images.unsplash.com/photo-1592205644721-2fe5214762ae?q=80&w=600&auto=format&fit=crop&ixlib=rb-4.0.3"
          alt="Background"
          className="h-full w-full rounded-3xl object-cover transition-all group-hover/clock:scale-105 group-hover/clock:blur-[1px]"
