import type { PanInfo } from "motion/react";
import { AnimatePresence, motion } from "motion/react";
import { useEffect, useState } from "react";

import { cn } from "@/lib/utils";

type Fund = {
  value: string;
  change: number;
  label: string;
};

interface FundWidgetProps {
  /**
   * The array which contains all the funds with their value, changes, and label.
   */
  funds: Fund[];

  /**
   * Class name for the background element.
   */
  backgroundClassName?: string;

  /**
   * Class name for the container element.
   */
  containerClassName?: string;
}

export default function FundWidget({
  funds = [
    { value: "2.7Cr", change: 12, label: "Stocks" },
    { value: "3.5Cr", change: -8, label: "Funds" },
    { value: "1.2Cr", change: 6, label: "Deposits" },
  ],
  backgroundClassName,
  containerClassName,
}: FundWidgetProps) {
  const len = funds.length;

  const [[activeDiv, direction], setDirection] = useState([0, 0]);
  const [dragDistance, setDragDistance] = useState(0);

  // Reset dragDistance after the drag ends to remove blur/rotate effects
  useEffect(() => {
    if (dragDistance !== 0) {
      const timer = setTimeout(() => {
        setDragDistance(0);
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [dragDistance]);

  const sliderVariants = {
    incoming: (direction: number) => ({
      y: direction > 0 ? "100%" : "-100%",
      scale: 1.0,
      opacity: 0,
    }),
    active: { y: 0, scale: 1, opacity: 1 },
    exit: (direction: number) => ({
      y: direction > 0 ? "100%" : "-100%",
      scale: 1,
      opacity: 0.2,
    }),
  };

  const sliderTransition = {
    duration: 0.5,
    ease: [0.56, 0.03, 0.12, 1.04] as [number, number, number, number],
  };

  const swipeToAction = (direction: number) => {
    const newDiv = activeDiv + direction;
    if (newDiv < 0 || newDiv >= len) return;

    setDirection([newDiv, direction]);
  };

  const draghandler = (dragInfo: PanInfo) => {
    const dragDistanceY = dragInfo.offset.y;
    const swipeThreshold = 20;

    // Only swipe down if not at the first div (activeDiv !== 0)
    if (dragDistanceY > swipeThreshold) {
      swipeToAction(-1);
    }
    // Only swipe up if not at the last div (activeDiv !== len - 1)
    else if (dragDistanceY < -swipeThreshold) {
      swipeToAction(1);
    }

    setDragDistance(0);
  };

  const skipToDiv = (divId: number) => {
    let changeDirection = 1;
    if (divId > activeDiv) {
      changeDirection = 1;
    } else if (divId < activeDiv) {
      changeDirection = -1;
    }
    setDirection([divId, changeDirection]);
  };

  const blurValue = Math.min(Math.abs(dragDistance / 20), 10);
  const rotateYValue = Math.min(dragDistance / 10, 15);

  return (
    <div className={cn("relative flex size-52 items-center justify-center", containerClassName)}>
      <AnimatePresence initial={false}>
        <div className="flex h-72 w-64 origin-center scale-[0.72] flex-col items-center">
          <div className="z-20 flex h-64 w-72 overflow-clip rounded-[35px] bg-white px-6 pt-6 shadow-[0px_0px_10px_1px_#bec2bf]">
            <motion.div
              key={activeDiv}
              custom={direction}
              className="block h-full w-full"
              variants={sliderVariants}
              initial="incoming"
              animate="active"
              transition={sliderTransition}
              drag="y"
              dragConstraints={{ top: 0, bottom: 0 }}
              dragElastic={1}
              onDragEnd={(_, dragInfo) => draghandler(dragInfo)}
              onDrag={(_event, info) => setDragDistance(info.offset.y)}
              style={{
                filter: `blur(${blurValue}px)`,
                transform: `rotateY(${rotateYValue}deg)`,
              }}
            >
              <div className="h-56 w-56 bg-white">
                <h1 className="mb-3 text-6xl font-bold">{funds[activeDiv].value}</h1>
                {funds[activeDiv].change < 0 ? (
                  <h2 className="text-2xl font-bold text-red-500">
                    {funds[activeDiv].change}% &#8595;
                  </h2>
                ) : (
                  <h2 className="text-2xl font-bold text-green-500">
                    {funds[activeDiv].change}% &#8593;
                  </h2>
                )}
                <h1 className="mb-2 mt-14 text-4xl font-bold text-gray-500">
                  {funds[activeDiv].label}
                </h1>
              </div>
            </motion.div>
            <div className="-my-2 flex h-full w-10 flex-col items-center justify-center">
              {funds.map((_, index) => {
                return (
                  <motion.span
                    key={index}
                    className="my-1 h-2 w-2 rounded-full bg-black"
                    style={{ backgroundColor: index === activeDiv ? "black" : "gray" }}
                    initial={{ height: 8 }}
                    animate={{ height: index === activeDiv ? 30 : 8 }}
                    onClick={() => skipToDiv(index)}
                  ></motion.span>
                );
              })}
            </div>
          </div>
          <div className="z-10 -mt-8 h-10 w-[270px] rounded-b-[35px] bg-white shadow-[0px_0px_5px_1px_#bec2bf]"></div>
        </div>
      </AnimatePresence>
    </div>
  );
}

"use client";

import { Circle, Triangle } from "lucide-react";
import { useEffect, useState } from "react";

import { cn } from "@/lib/utils";

interface Team {
  score: number;
  win: number;
  name: string;
  icon: string;
}

interface GameInfo {
  teamOne: Team;
  teamTwo: Team;
  lap: number;
}

// #region placeholder functions
const maxScore = 10;
const lapCount = 5;

const getScore = (lastScore?: GameInfo): GameInfo => {
  const teamOneScore = (lastScore?.teamOne.score ?? 0) + Math.floor(Math.random() * 3) + 1;
  const teamTwoScore = (lastScore?.teamTwo.score ?? 0) + Math.floor(Math.random() * 3) + 1;

  return {
    lap: (lastScore?.lap ?? 1) + 1,
    ...lastScore,
    teamOne: {
      icon: "🇳🇵",
      name: "NPL",
      score: teamOneScore % maxScore,
      win:
        teamOneScore >= maxScore
          ? (lastScore?.teamOne.win ?? 0) + 1
          : (lastScore?.teamOne.win ?? 0),
    },
    teamTwo: {
      name: "USA",
      icon: "🇺🇸",
      score: teamTwoScore % maxScore,
      win:
        teamTwoScore >= maxScore
          ? (lastScore?.teamTwo.win ?? 0) + 1
          : (lastScore?.teamTwo.win ?? 0),
    },
  };
};

// #endregion

const Header = ({ game }: { game: GameInfo }) => (
  <div className="flex items-center justify-between p-4">
    <div className="flex gap-1">
      <div className="h-6 w-6">{game.teamOne.icon}</div>
      <p className="font-bold">{game.teamOne.name}</p>
    </div>
    <div className="flex gap-1">
      <p className="font-bold">{game.teamTwo.name}</p>
      <div className="h-6 w-6">{game.teamTwo.icon}</div>
    </div>
  </div>
);

const Score = ({ score }: { score: string }) => (
  <div className="relative flex h-20 w-10 items-center justify-center rounded-lg border-4 border-black bg-neutral-800">
    <p className="text-5xl font-semibold">{score}</p>
    <div className="absolute w-full border border-black"></div>
  </div>
);

const Diamond = ({ style }: { style: string }) => (
  <div className={cn("absolute h-1.5 w-1.5 rotate-45 transform bg-gray-500", style)} />
);

export default function LiveScore() {
  // #region state
  const [game, updateGame] = useState<GameInfo>({
    teamOne: {
      score: Math.floor(Math.random() * maxScore),
      win: Math.floor(Math.random() * 3),
      name: "NPL",
      icon: "🇳🇵",
    },
    teamTwo: {
      score: Math.floor(Math.random() * maxScore),
      win: Math.floor(Math.random() * 3),
      name: "USA",
      icon: "🇺🇸",
    },
    lap: Math.floor(Math.random() * 3) + 1,
  });

  useEffect(() => {
    let timer: NodeJS.Timeout;

    const updateScore = () => {
      const now = new Date();
      const secondsUntilNextMinute = 60 - now.getSeconds();
      timer = setTimeout(updateScore, secondsUntilNextMinute * 1000);
      updateGame((current) => {
        const next = getScore(current);
        if (next.lap === lapCount) {
          clearTimeout(timer);
        }
        return next;
      });
    };

    const timeoutId = setTimeout(updateScore, 0);

    return () => clearTimeout(timeoutId);
  }, []);

  // #endregion

  return (
    <div className="group/score flex size-52 flex-col rounded-3xl bg-zinc-800 text-white">
      <Header game={game} />
      <div className="flex w-full flex-1 items-center justify-center gap-2 px-4">
        <div className="flex">
          <Score score={String(game.teamOne.score).padStart(2, "0").charAt(0)} />
          <Score score={String(game.teamOne.score).padStart(2, "0").charAt(1)} />
        </div>
        <div className="flex">
          <Score score={String(game.teamTwo.score).padStart(2, "0").charAt(0)} />
          <Score score={String(game.teamTwo.score).padStart(2, "0").charAt(1)} />
        </div>
      </div>

      <div className="relative h-14 overflow-hidden rounded-b-3xl bg-zinc-950 text-white">
        <div className="flex h-14 items-center justify-around overflow-hidden p-4 font-medium transition-transform group-hover/score:-translate-y-full">
          <div className="flex items-center gap-1 tabular-nums">
            <Triangle fill="white" size={6} />
            <p>
              {game.lap}
              <sup>{["st", "nd", "rd"][game.lap - 1] ?? "th"}</sup>
            </p>
          </div>
          <div className="flex flex-col items-center justify-center">
            <div className="relative h-3 w-3">
              <Diamond style="bg-yellow-500 -top-1/4 left-1/4 " />
              <Diamond style="-left-1/4 top-1/4 " />
              <Diamond style="-right-1/4 top-1/4 " />
            </div>
            <div className="flex pt-1">
              <Circle size={8} fill="white" />
              <Circle size={8} color="grey" />
              <Circle size={8} color="grey" />
            </div>
          </div>
          <div className="tabular-nums">
            {game.teamOne.win} - {game.teamTwo.win}
          </div>
        </div>
        <div className="flex h-14 items-center justify-center bg-green-500 text-sm transition-transform group-hover/score:-translate-y-full">
          Some other information.
        </div>
      </div>
    </div>
  );
}

