export default function ReminderWidget({
  className,
  title = "Packing",
  items = DEFAULT_ITEMS,
}: ReminderWidgetProps) {
  const itemsRef = useRef<ReminderWidgetItem[] | null>(null);
  const [rows, setRows] = useState<ReminderWidgetItem[]>([]);

  if (items !== itemsRef.current) {
    itemsRef.current = items;
    setRows(items);
  }

  const remaining = rows.filter((item) => !item.done).length;

  const toggle = (id: string) => {
    setRows((prev) => prev.map((item) => (item.id === id ? { ...item, done: !item.done } : item)));
  };

  return (
    <div
      className={cn(
        "flex h-80 w-52 overflow-hidden relative flex-col rounded-3xl border border-border bg-card font-sans shadow-md",
        className,
      )}
    >
