          />
        ))}
        <YourImageSlot minimize={minimize} imageAlternate="Your Name" imageSource={Music} />
      </motion.div>
    </motion.div>
  );
}

"use client";

import { FlagIcon, ShieldBan, ShieldCheck } from "lucide-react";
import { useState } from "react";

import { cn } from "@/lib/utils";

type SlidingButtonProps = {
  connected: boolean;
  onConnectedChange: (connected: boolean) => void;
  className?: string;
};

function SlidingButton({ connected, onConnectedChange, className }: SlidingButtonProps) {
  return (
    <button
      type="button"
      role="switch"
      aria-checked={connected}
      className={cn(
        "touch-manipulation relative flex min-h-11 w-full items-center justify-between overflow-hidden rounded-2xl bg-muted transition-colors",
        className,
      )}
      onClick={() => onConnectedChange(!connected)}
    >
      <span className="flex h-11 w-8 items-center justify-center" aria-hidden>
        <span
          className={cn("size-2.5 rounded-full bg-red-500 transition-opacity", {
            "opacity-0": connected,
            "opacity-100": !connected,
          })}
        />
      </span>
      <span
        className={cn(
          "absolute z-10 flex h-10 w-[8.75rem] flex-col items-center justify-center rounded-[14px] bg-background py-1 shadow-sm transition-[left] duration-200 ease-out",
          connected ? "left-0.5" : "left-[34px]",
        )}
      >
        <span className="text-sm font-semibold text-foreground">
          {connected ? "Connected" : "Disconnected"}
        </span>
        <span
          className={cn("inline-flex items-center gap-1 text-xs font-medium", {
            "text-sky-700 dark:text-sky-400": connected,
            "text-red-700 dark:text-red-400": !connected,
          })}
        >
          {connected ? <ShieldCheck size={12} aria-hidden /> : <ShieldBan size={12} aria-hidden />}
          {connected ? "Secured" : "Not secured"}
        </span>
      </span>
      <span className="flex h-11 w-8 items-center justify-center" aria-hidden>
        <span
          className={cn("size-2.5 rounded-full bg-emerald-500 transition-opacity", {
            "opacity-0": !connected,
            "opacity-100": connected,
          })}
        />
      </span>
    </button>
  );
}

export type VpnConnectionProps = {
  className?: string;
  serverName?: string;
  latency?: string;
  downloadMbps?: string;
  defaultConnected?: boolean;
  connected?: boolean;
  onConnectedChange?: (connected: boolean) => void;
};

export default function VpnConnection({
  className,
  serverName = "Tokyo",
  latency = "53 ms",
  downloadMbps = "57.4",
  defaultConnected = false,
  connected: controlledConnected,
  onConnectedChange,
}: VpnConnectionProps) {
  const [internalConnected, setInternalConnected] = useState(defaultConnected);
  const connected = controlledConnected ?? internalConnected;

  const setConnected = (next: boolean) => {
    if (controlledConnected === undefined) {
      setInternalConnected(next);
    }
    onConnectedChange?.(next);
  };

  return (
    <div className={className}>
      <div className="flex size-52 flex-col rounded-3xl border border-sky-900/30 bg-sky-950 p-0.5 shadow-md">
        <div className="flex items-center gap-2 px-3 pb-1.5 pt-3">
          <FlagIcon className="size-5 fill-amber-400 text-amber-400" aria-hidden />
          <p className="truncate text-sm font-semibold tracking-tight text-amber-400">
            {serverName}
          </p>
        </div>
        <div className="flex min-h-0 flex-1 flex-col gap-2 rounded-[22px] bg-background p-3">
          <div className="inline-flex max-w-fit items-center gap-1.5 rounded-lg bg-emerald-500/15 px-2 py-0.5">
            <span className="size-2 animate-pulse rounded-full bg-emerald-500" aria-hidden />
            <span className="text-xs font-medium tabular-nums text-emerald-700 dark:text-emerald-400">
              {latency}
            </span>
          </div>
          <p className="text-3xl font-semibold tabular-nums tracking-tight text-foreground">
            {downloadMbps}
            <span className="ml-0.5 text-sm font-medium text-muted-foreground">Mbps</span>
          </p>
          <div className="mt-auto">
            <SlidingButton connected={connected} onConnectedChange={setConnected} />
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { Droplet } from "lucide-react";
import { useState } from "react";

import { cn } from "@/lib/utils";

export type WaterTrackerProps = {
  className?: string;
  dailyGoal?: number;
  sipMl?: number;
  defaultIntake?: number;
  intake?: number;
  onIntakeChange?: (ml: number) => void;
};

export default function WaterTracker({
  className,
  dailyGoal = 2000,
  sipMl = 250,
  defaultIntake = 750,
  intake: controlledIntake,
  onIntakeChange,
}: WaterTrackerProps) {
  const [internalIntake, setInternalIntake] = useState(defaultIntake);
  const intake = controlledIntake ?? internalIntake;
  const atGoal = intake >= dailyGoal;
  const progress = Math.min(100, (intake / dailyGoal) * 100);

  const addWater = () => {
    if (atGoal) return;
    const next = Math.min(dailyGoal, intake + sipMl);
    if (controlledIntake === undefined) {
      setInternalIntake(next);
    }
    onIntakeChange?.(next);
  };

  return (
    <div
      className={cn(
        "relative flex size-52 overflow-hidden rounded-3xl border border-border bg-card font-sans shadow-md",
        className,
      )}
    >
      <div className="flex min-w-0 flex-1 flex-col p-4">
        <div className="flex shrink-0 items-center gap-1.5">
          <Droplet className="size-[15px] fill-sky-500 text-sky-500" aria-hidden />
          <p className="text-[15px] font-semibold leading-none text-foreground">Water</p>
        </div>

        <div className="mt-3 flex flex-col gap-1">
          <p className="text-[22px] font-normal leading-none tabular-nums tracking-tight text-foreground">
            {intake.toLocaleString()}
            <span className="text-[13px] font-medium text-muted-foreground"> ml</span>
          </p>
          <p className="text-[13px] leading-none text-muted-foreground">
            of {dailyGoal.toLocaleString()} ml today
          </p>
        </div>

        <button
          type="button"
          onClick={addWater}
          disabled={atGoal}
          className={cn(
            "touch-manipulation mt-auto min-h-11 w-full rounded-full text-[15px] font-medium leading-none transition-transform",
            atGoal
              ? "cursor-not-allowed bg-muted text-muted-foreground"
              : "bg-sky-600 text-white hover:scale-[1.02] active:scale-[0.98]",
          )}
        >
          +{sipMl} ml
        </button>
      </div>

      <div className="relative w-10 shrink-0 border-l border-border bg-muted/30" aria-hidden>
        <div
          className="absolute inset-x-0 bottom-0 bg-linear-to-t from-sky-600 to-sky-400 transition-[height] duration-300 ease-out"
          style={{ height: `${progress}%` }}
        />
      </div>
    </div>
  );
}

import { CircleArrowUp, CloudSunRain } from "lucide-react";

import { cn } from "@/lib/utils";

export type WeatherCardProps = {
  className?: string;
  city?: string;
  temperature?: number;
  feelsLike?: number;
  high?: number;
  low?: number;
};

export default function WeatherCard({
  className,
  city = "Tokyo",
  temperature = 19,
  feelsLike = 21,
  high = 24,
  low = 9,
}: WeatherCardProps) {
  return (
    <div
      className={cn(
        "flex size-52 flex-col rounded-3xl border border-border bg-linear-to-br from-muted/80 to-muted p-4 font-sans shadow-md",
        className,
      )}
    >
      <div className="flex min-h-0 flex-1 flex-col justify-start gap-2">
        <p className="text-[15px] font-semibold leading-none text-foreground">{city}</p>
        <div className="flex items-start gap-2">
          <CloudSunRain
            className="mt-1 size-8 shrink-0 text-foreground/75"
            strokeWidth={1.75}
            aria-hidden
          />
          <p className="text-[34px] font-normal leading-none tabular-nums tracking-tight text-foreground">
            {temperature}&deg;
          </p>
        </div>
        <p className="text-[13px] leading-none text-muted-foreground">
          Feels like <span className="tabular-nums">{feelsLike}&deg;</span>
        </p>
      </div>
      <div className="flex shrink-0 justify-between rounded-xl border border-border/60 bg-background/50 px-2.5 py-2 text-[13px] font-medium tabular-nums leading-none backdrop-blur-sm">
        <div className="flex items-center gap-1 text-orange-600 dark:text-orange-300">
          <CircleArrowUp className="size-3.5" strokeWidth={2} aria-hidden />
          {high}&deg;
        </div>
        <span className="text-border/80" aria-hidden>
          |
        </span>
        <div className="flex items-center gap-1 text-sky-700 dark:text-sky-300">
          <CircleArrowUp className="size-3.5 rotate-180" strokeWidth={2} aria-hidden />
          {low}&deg;
        </div>
      </div>
    </div>
  );
}
